async function loadIncludes(){const e=Array.from(document.querySelectorAll("[data-include]"));0!==e.length&&await Promise.all(e.map(async e=>{const t=(e.getAttribute("data-include")||"").trim();if(t)try{const a=await fetch(t,{cache:"no-cache"});if(!a.ok)throw new Error(`HTTP ${a.status}`);let c=await a.text();if(t.startsWith("../")){const e=t.substring(0,t.lastIndexOf("/")+1).replace("partials/","").replace("components/","");c=c.replace(/(src|href|data-src)=".\//g,`$1="${e}`)}e.innerHTML=c,e.removeAttribute("data-include"),window.AOS&&window.AOS.refresh()}catch(e){console.warn("Include failed:",t,e)}}))}window.__includesReady=loadIncludes();